#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_M 101
#define MAX_N 101
#define MAX_X 101

int min_steps = -1;

void bfs(int m, int n, char maze[m + 1][n + 1], int x, int i, int j, int current_sum, int steps, int visited[m + 1][n + 1][MAX_X]) {
    if (i < 0 || i >= m || j < 0 || j >= n || maze[i][j] == '#' || visited[i][j][current_sum]) return;
    visited[i][j][current_sum] = 1;
    if (maze[i][j] >= '0' && maze[i][j] <= '9') current_sum += maze[i][j] - '0';
    if (current_sum > x) return;
    if (current_sum == x) {
        if (min_steps == -1 || steps < min_steps) min_steps = steps;
        return;
    }
    bfs(m, n, maze, x, i - 1, j, current_sum, steps + 1, visited);
    bfs(m, n, maze, x, i + 1, j, current_sum, steps + 1, visited);
    bfs(m, n, maze, x, i, j - 1, current_sum, steps + 1, visited);
    bfs(m, n, maze, x, i, j + 1, current_sum, steps + 1, visited);
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int m, n;
        scanf("%d %d", &m, &n);
        char maze[m + 1][n + 1];
        for (int i = 0; i < m; i++) scanf("%s", maze[i]);
        int x;
        scanf("%d", &x);
        int start_i, start_j;
        for (int i = 0; i < m; i++) for (int j = 0; j < n; j++) if (maze[i][j] == '*') {
            start_i = i;
            start_j = j;
            break;
        }
        int visited[m + 1][n + 1][MAX_X];
        for (int i = 0; i <= m; i++) for (int j = 0; j <= n; j++) for (int k = 0; k <= x; k++) visited[i][j][k] = 0;
        min_steps = -1;
        bfs(m, n, maze, x, start_i, start_j, 0, 0, visited);
        printf("%d\n", min_steps);
    }
    return 0;
}

